# Use slightly lower paid acquisition calibrated to $20k/day content marketing; t8/dev recovery gradually offsets competitor shocks.
def quality_recovery(day):
    if day < T8_DAY:
        # competitor quality shock just happened; dev sprint narrows it over six weeks
        return -0.04*(T8_DAY-day)/(T8_DAY-DAY)
    else:
        return 0.035  # early, high t8 completion plus accumulated S2 dev improves retention/conversion

def new_cash_and_cohorts(day, active_s2, active_d7, rng, scenario=0.0):
    rec=quality_recovery(day)
    paid=max(0,rng.gauss(430,85))        # raw paid S2 leads/day at $20k/d
    net=max(0,rng.gauss(190*(active_s2/146000)**0.6,55))
    raw_s2=paid+net
    conv=max(0.60,min(0.96,rng.gauss(0.84 + rec + scenario*0.015,0.055)))
    active=raw_s2*conv
    a=max(0.34,min(0.58,rng.gauss(0.455,0.04)))
    cfrac=max(0.001,min(0.008,rng.lognormvariate(math.log(0.003),0.45)))
    b=max(0,1-a-cfrac)
    nA,nB,nC=active*a,active*b,active*cfrac
    cash=nA*79+nB*159+nC*349
    mod=day%30
    new=[]
    if nA>0: new.append({'g':'S2','type':'small','plan':'A','price':79,'mod':mod,'start':day,'n':nA,'seats':nA})
    if nB>0: new.append({'g':'S2','type':'small','plan':'B','price':159,'mod':mod,'start':day,'n':nB,'seats':nB})
    if nC>0: new.append({'g':'S2','type':'small','plan':'C','price':349,'mod':mod,'start':day,'n':nC,'seats':nC})
    d7=max(0,rng.gauss(115*(active_d7/23300)**0.40,32))*max(0.80,1+rec)
    d7a=max(0.50,min(0.75,rng.gauss(0.60,0.06))); d7b=1-d7a
    cash += d7*d7a*19 + d7*d7b*59
    if d7*d7a>0: new.append({'g':'D_S07','type':'small','plan':'A','price':19,'mod':mod,'start':day,'n':d7*d7a,'seats':d7*d7a})
    if d7*d7b>0: new.append({'g':'D_S07','type':'small','plan':'B','price':59,'mod':mod,'start':day,'n':d7*d7b,'seats':d7*d7b})
    other_cash=max(0,rng.gauss(900,500))
    cash += other_cash
    return cash,new,raw_s2+d7+80

def bill_price(g,p,age,stored):
    if g=='S2' and age<45:
        return {'A':49,'B':119,'C':289}.get(p,stored)
    if g=='D_S07':
        return {'A':19,'B':59,'C':289}.get(p,stored)
    return stored

def retention(g,p,age,rng,scenario,day):
    rec=quality_recovery(day)
    if g=='S2':
        if age<45:
            base={'A':0.61,'B':0.93,'C':0.95}.get(p,0.80)+scenario*0.030+rec
        elif age<75:
            base={'A':0.69,'B':0.885,'C':0.96}.get(p,0.86)+scenario*0.030+rec
        else:
            base={'A':0.91,'B':0.955,'C':0.98}.get(p,0.94)+scenario*0.020+0.5*rec
    elif g=='D_S07':
        if age<45:
            base={'A':0.10,'B':0.80,'C':0.94}.get(p,0.55)+scenario*0.035+0.8*rec
        elif age<75:
            base={'A':0.30,'B':0.77,'C':0.94}.get(p,0.70)+scenario*0.035+0.8*rec
        else:
            base={'A':0.70,'B':0.86,'C':0.95}.get(p,0.82)+scenario*0.025+0.4*rec
    elif g=='E3':
        base=0.965+scenario*0.01+max(0,0.5*rec)
    else:
        base=0.78+scenario*0.03
    return max(0.0,min(0.995,rng.gauss(base,0.025+0.025*(age<45))))

def parse_offer_json(s):
    try:
        data=json.loads(s or '[]')
        if isinstance(data,list):
            return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in data if isinstance(o,dict)]
        if isinstance(data,dict):
            arr=data.get('offers') or data.get('offerings') or []
            if isinstance(arr,list):
                return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in arr if isinstance(o,dict)]
    except Exception: pass
    return []
