                d={k:v for k,v in offers if k and v}
                u=rng.random()
                if g in ('E1','D_E09','D_E02') and 'A' in d and u<0.50: plan='A'
                elif 'B' in d and u<0.88: plan='B'
                elif 'C' in d: plan='C'
                elif 'B' in d: plan='B'
                else: plan='A'
                price=d.get(plan, list(d.values())[0])
                events.append({'day':DAY+delay,'g':g,'type':'large','plan':plan,'price':price,'mod':(DAY+delay)%30,'start':DAY+delay,'n':1,'seats':seats})
    return events

def ent_compute_per_seat_day(g,p):
    # monthly-ish unit economics calibrated from active E3 and insights; rough but conservative
    if p=='A': base={'E1':0.11,'E2':0.44,'E3':0.25,'D_E02':0.19,'D_E07':0.35,'D_E08':0.24,'D_E09':0.16}.get(g,0.25)
    elif p=='B': base={'E1':0.31,'E2':1.33,'E3':0.74,'D_E02':0.56,'D_E07':1.04,'D_E08':0.72,'D_E09':0.48}.get(g,0.75)
    else: base={'E1':0.62,'E2':2.66,'E3':1.48,'D_E02':1.12,'D_E07':2.08,'D_E08':1.44,'D_E09':0.96}.get(g,1.5)
    return base

def simulate(days,seed):
    rng=random.Random(seed)
    scenario=max(-1.7,min(1.7,rng.gauss(0,0.6)))
    cash=cash0
    active=[c.copy() for c in coh+ent]
    events=ent_events(days,rng,scenario)
    shock_day=None; shock_mag=0
    if rng.random()<0.16*days/84:
        shock_day=DAY+rng.randint(5,max(6,days)); shock_mag=rng.uniform(0.04,0.16)
    for day in range(DAY+1,DAY+days+1):
        rel=day-DAY
        # new enterprise contracts pay immediately and then join monthly billing/cost base
        for e in [x for x in events if x['day']==day]:
            cash += e['price']*e['seats']
            active.append(e.copy())
        shock_factor=1.0
        if shock_day and day>=shock_day:
            shock_factor=max(0.75,1-shock_mag)
        active_s2=sum(c['seats'] for c in active if c['g']=='S2')
        active_d7=sum(c['seats'] for c in active if c['g']=='D_S07')
        ncash,new,leads=new_cash_and_cohorts(day,active_s2,active_d7,rng,shock_factor)
        cash += ncash
        active.extend(new)
        cash -= leadcost_per_day
        newactive=[]
        for c in active:
            key=(c['g'],c['plan'])
            if c['type']=='large': comp=ent_compute_per_seat_day(c['g'],c['plan'])
            else: comp=comp_per_seat_day.get(key, {'A':0.33,'B':1.02,'C':1.9}.get(c['plan'],1.0))
            cash -= comp*c['seats']
            if day%30 == c['mod']:
                age=day-c['start']
                ret=retention(c['g'],c['plan'],age,rng,scenario)
                if shock_day and day>=shock_day and c['g'] in ('S2','D_S07'):
                    ret=max(0,ret-shock_mag)
                kept=c['n']*ret; kept_seats=c['seats']*ret
                if kept>0:
                    price=bill_price(c['g'],c['plan'],age,c['price'])
                    cash += price*kept_seats
                    cc=c.copy(); cc['n']=kept; cc['seats']=kept_seats; cc['price']=price
                    newactive.append(cc)
            else:
                newactive.append(c)
        active=newactive
        # Future management likely tapers D_S07/S2 ops after 8 weeks if stable; add enterprise capacity/ops if seats close.
        fixed=fixed_per_day
        if rel>56:
            s2=sum(c['seats'] for c in active if c['g']=='S2')
            d7=sum(c['seats'] for c in active if c['g']=='D_S07')
            entseats=sum(c['seats'] for c in active if c['type']=='large')
            ops = 5000 + 245000*(max(s2,1)/145000)**0.52 + 45000*(max(d7,1)/22500)**0.60 + 9600
            dev = 5000 + 12000*(max(s2,1)/145000)**0.35 + 2000*(max(d7,1)/22500)**0.35 + 7250
            cap = 75000 if entseats>250000 or sum(c['seats'] for c in active)>260000 else 28000
            entops = min(80000, 0.12*max(0,entseats-50000))
            fixed = ops+dev+20000+cap+entops
            fixed=max(260000,min(520000,fixed))
        cash -= fixed
    return cash

for days in [7,28,84,182]:
    nseeds = 220 if days<=28 else (140 if days<=84 else 90)
    vals=[simulate(days,20000+i) for i in range(nseeds)]
